sub select_perl_script {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::select_perl_script <event_handler>
    # end wxGlade


    my $dlg = Wx::FileDialog->new(
        $self,
        "Select Perl Script",
        "", "",
        join('|',
            "Perl scripts (*.pl)", "*.pl",
            "Perl modules (*.pm)", "*.pm",
            "Extensionless files (*)", "*",
            "Perl-related (*.pl;*.pm;*)", "*.pl;*.pm;*",
            "All files (*.*)", "*.*",
        ),
        Wx::wxFD_OPEN() | Wx::wxFD_FILE_MUST_EXIST()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
