sub _extract_makefile_from_text {
    my ($self, $text) = @_;

    $text //= '';
    return '' if $text eq '';

    my $found = '';
    while ($text =~ /(# -- BEGIN MAKEFILE --.*?# -- END MAKEFILE --\s*)/sg) {
        $found = $1;
    }

    return $found;
}

sub _current_makefile_text {
    my ($self) = @_;

    my $text = $self->{txt_cmd_io}->GetValue // '';
    my $makefile = $self->_extract_makefile_from_text($text);
    $makefile ||= $self->{_generated_makefile} || '';

    return $makefile;
}

sub _write_makefile_file {
    my ($self, $path, $makefile) = @_;

    return 0 if !_trim($path);
    return 0 if !_trim($makefile);

    if (open(my $fh, '>', $path)) {
        binmode($fh);
        print {$fh} $makefile;
        close($fh);
        return 1;
    }

    return 0;
}

sub _parse_makefile_vars {
    my ($self, $text) = @_;

    my %vars;
    $text //= '';

    for my $line (split /\r?\n/, $text) {
        next if $line =~ /^\s*#/;
        if ($line =~ /^\s*([A-Za-z_][A-Za-z0-9_]*)\s*:?=\s*(.*?)\s*$/) {
            my ($key, $val) = ($1, $2);
            $val =~ s/^"(.*)"$/$1/;
            $val =~ s/^'(.*)'$/$1/;
            $vars{uc $key} = $val;
        }
    }

    return \%vars;
}

sub _resolve_exe_from_makefile {
    my ($self, $makefile_text) = @_;

    my $vars = $self->_parse_makefile_vars($makefile_text);
    my $exe  = _trim($vars->{EXE});
    my $dist = _trim($vars->{DIST});

    return ('', '', 'No EXE variable was found in the loaded Makefile.') if !$exe;

    my $makefile_path = _trim($self->{_makefile_saved_path});
    return ('', '', 'The Makefile must be saved or loaded from disk before the EXE can be run.') if !$makefile_path;

    my $make_dir = File::Basename::dirname($makefile_path);

    my @candidates;
    push @candidates, $exe;
    push @candidates, File::Spec->catfile($dist, $exe) if $dist && $exe !~ m{[\/]} && $exe !~ /^[A-Za-z]:/;

    my %seen;
    @candidates = grep { !$seen{$_}++ } @candidates;

    for my $candidate (@candidates) {
        my $path = $candidate;

        if ($path !~ /^[A-Za-z]:/ && $path !~ m{^[\/]}) {
            $path = File::Spec->catfile($make_dir, $path);
        }

        return ($path, $exe, '') if -f $path;
    }

    my $first = $candidates[0];
    my $first_path = $first;
    if ($first_path !~ /^[A-Za-z]:/ && $first_path !~ m{^[\/]}) {
        $first_path = File::Spec->catfile($make_dir, $first_path);
    }

    return ($first_path, $exe, 'The EXE defined in the Makefile could not be found on disk yet.');
}

sub run_exe_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::run_exe_file <event_handler>
    # end wxGlade

    if (!$self->{_makefile_has_run}) {
        Wx::MessageBox(
            "Please run the Makefile successfully before using 'Run EXE'.",
            "Run EXE",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    my $makefile_text = $self->_current_makefile_text();
    if (!$makefile_text) {
        Wx::MessageBox(
            "No Makefile text is available to inspect.",
            "Run EXE",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    my ($exe_path, $exe_value, $err) = $self->_resolve_exe_from_makefile($makefile_text);
    if ($err) {
        Wx::MessageBox(
            $err . "\n\nExpected EXE value: " . ($exe_value || '(not found)') . "\nPath checked: " . ($exe_path || '(none)'),
            "Run EXE",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    my $run_dir = File::Basename::dirname($exe_path);

    $self->_append_io("\n=== Running EXE ===\n");
    $self->_append_io("[exe] EXE=$exe_value\n");
    $self->_append_io("[exe] Path=$exe_path\n\n");

    my $q = $self->{_q};

    threads->create(sub {
        my ($path, $dir, $qref) = @_;

        my $orig = eval { Cwd::getcwd() } || '';
        my $exit = 0;

        if (!chdir $dir) {
            $qref->enqueue("[worker][error] failed to chdir to '$dir': $!\n");
            $qref->enqueue("[exe done] exit_code=1\n");
            return;
        }

        $qref->enqueue("[worker] current directory: $dir\n");
        $qref->enqueue("[worker] starting: $path\n");

        my $cmd = qq{"$path" 2>&1};

        if (open(my $fh, "$cmd |")) {
            while (my $line = <$fh>) {
                $qref->enqueue($line);
            }
            close($fh);
            $exit = $? >> 8;
        } else {
            $qref->enqueue("[worker][error] failed to run EXE '$path': $!\n");
            $exit = 127;
        }

        chdir $orig if $orig;

        $qref->enqueue("[exe done] exit_code=$exit\n");
        return;
    }, $exe_path, $run_dir, $q)->detach();
}

sub load_makefile_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::load_makefile_file <event_handler>
    # end wxGlade

    my $default_dir  = $self->{_proj_root} || '';
    my $default_name = 'Makefile';

    if ($self->{_makefile_saved_path}) {
        $default_dir  = File::Basename::dirname($self->{_makefile_saved_path});
        $default_name = File::Basename::basename($self->{_makefile_saved_path});
    }

    my $dlg = Wx::FileDialog->new(
        $self,
        "Load Makefile",
        $default_dir,
        $default_name,
        "Makefile (Makefile)|Makefile|Text files (*.txt)|*.txt|All files (*.*)|*.*",
        Wx::wxFD_OPEN() | Wx::wxFD_FILE_MUST_EXIST()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;
        my $text = '';

        if (open(my $fh, '<', $path)) {
            local $/;
            binmode($fh);
            $text = <$fh>;
            close($fh);

            $self->{txt_cmd_io}->SetValue($text // '');
            $self->{txt_cmd_io}->SetInsertionPoint(0);
            $self->{txt_cmd_io}->ShowPosition(0);

            $self->{_generated_makefile}  = $text // '';
            $self->{_makefile_saved_path} = $path;

            $self->_reset_run_exe_state();
            $self->_refresh_run_makefile_button_state();

            Wx::MessageBox(
                "Loaded:\n$path",
                "Load Makefile",
                wxOK | wxICON_INFORMATION,
                $self
            );
        } else {
            Wx::MessageBox(
                "Failed to load:\n$path\n\n$!",
                "Load Makefile",
                wxOK | wxICON_ERROR,
                $self
            );
        }
    }

    $dlg->Destroy;
}

sub save_makefile_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::save_makefile_file <event_handler>
    # end wxGlade

    my $makefile = $self->_current_makefile_text();
    if (!$makefile) {
        Wx::MessageBox(
            "Nothing to save yet.\n\nRun 'Find DLLs' first so the Makefile can be generated.",
            "Save Makefile",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    my $default_dir  = $self->{_proj_root} || '';
    my $default_name = 'Makefile';

    if ($self->{_makefile_saved_path}) {
        $default_dir  = File::Basename::dirname($self->{_makefile_saved_path});
        $default_name = File::Basename::basename($self->{_makefile_saved_path});
    }

    my $dlg = Wx::FileDialog->new(
        $self,
        "Save Makefile",
        $default_dir,
        $default_name,
        "Makefile (Makefile)|Makefile|Text files (*.txt)|*.txt|All files (*.*)|*.*",
        Wx::wxFD_SAVE() | Wx::wxFD_OVERWRITE_PROMPT()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;

        if ($self->_write_makefile_file($path, $makefile)) {
            $self->{_makefile_saved_path} = $path;
            $self->{_generated_makefile}  = $makefile;
            $self->_reset_run_exe_state();
            $self->_append_io("[makefile] Saved: $path\n");
            $self->_refresh_run_makefile_button_state();
            Wx::MessageBox("Saved:\n$path", "Save Makefile", wxOK | wxICON_INFORMATION, $self);
        } else {
            Wx::MessageBox("Failed to save:\n$path\n\n$!", "Save Makefile", wxOK | wxICON_ERROR, $self);
        }
    }

    $dlg->Destroy;
}

sub run_makefile_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::run_makefile_file <event_handler>
    # end wxGlade


    my $makefile_path = _trim($self->{_makefile_saved_path});
    if (!$makefile_path) {
        Wx::MessageBox(
            "Please click 'Save Makefile' first.",
            "Run Makefile",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    my $makefile_text = $self->_current_makefile_text();
    if (!$makefile_text) {
        Wx::MessageBox(
            "No Makefile text was found in the output window.",
            "Run Makefile",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    if (!$self->_write_makefile_file($makefile_path, $makefile_text)) {
        Wx::MessageBox(
            "Failed to update the saved Makefile before running.\n\n$!",
            "Run Makefile",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    my $make_dir = File::Basename::dirname($makefile_path);
    if (!-d $make_dir) {
        Wx::MessageBox(
            "Makefile directory not found:\n$make_dir",
            "Run Makefile",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    $self->{button_2}->Enable(0) if $self->{button_2};
    $self->_reset_run_exe_state();
    $self->_append_io("\n=== Running Makefile ===\n");
    $self->_append_io("[makefile] Saved path: $makefile_path\n");
    $self->_append_io("[makefile] cd $make_dir\n");
    $self->_append_io("[makefile] gmake all\n\n");

    my $q = $self->{_q};

    threads->create(sub {
        my ($dir, $qref) = @_;

        my $orig = eval { Cwd::getcwd() } || '';
        my $exit = 0;

        if (!chdir $dir) {
            $qref->enqueue("[worker][error] failed to chdir to '$dir': $!\n");
            $qref->enqueue({ type => 'MAKE_DONE', exit_code => 1 });
            return;
        }

        $qref->enqueue("[worker] current directory: $dir\n");

        if (open(my $fh, 'gmake all 2>&1 |')) {
            while (my $line = <$fh>) {
                $qref->enqueue($line);
            }
            close($fh);
            $exit = $? >> 8;
        } else {
            $qref->enqueue("[worker][error] failed to run gmake all: $!\n");
            $exit = 127;
        }

        chdir $orig if $orig;

        $qref->enqueue({ type => 'MAKE_DONE', exit_code => $exit });
        return;
    }, $make_dir, $q)->detach();
}

sub run_pp_autolink {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::run_pp_autolink <event_handler>
    # end wxGlade

    my $script = $self->{perl_script_path}->GetValue // '';
    $script =~ s/^\s+|\s+$//g;

    my $exe = $script;
    $exe =~ s/\.pl//g;
    $exe .= ".exe";

    if (!$script) {
        $self->_append_io("[error] No .pl selected.\n");
        return;
    }
    if (!-f $script) {
        $self->_append_io("[error] File not found: $script\n");
        return;
    }

    $script = Cwd::abs_path($script) || $script;

    $self->_compute_project_layout_from_script($script);
    $self->{_iss_pending_seed} = 1;
    my $cur = $self->{notebook_1}->GetSelection;
    if (defined($cur) && $cur == 1) {
        $self->_seed_iss_fields_from_script();
    }

    $self->{button_3}->Enable(0);
    $self->{_generated_makefile}  = '';
    $self->{_makefile_saved_path} = '';
    $self->_reset_run_exe_state();
    $self->_refresh_run_makefile_button_state();
    $self->_append_io("\n=== Starting pp_ autolink scan ===\n\n");

    my $q = $self->{_q};

    threads->create(sub {
        my ($script_path, $qref) = @_;

        $qref->enqueue("[worker] thread started\n\n");

        my $pp_ver = `pp --version 2>&1`;
        my $pp_rc  = $? >> 8;
        $qref->enqueue("[worker] pp --version rc=$pp_rc\n$pp_ver");

        if ($pp_rc != 0) {
            $qref->enqueue("[worker][error] 'pp_autolink' command failed. Is PAR::Packer installed and on PATH?\n");
            $qref->enqueue({ type => 'DONE', exit_code => $pp_rc });
            return;
        }

        my @cmd = qw/pp_autolink -o tmp.exe/;
        push @cmd, $script_path;

        my $pretty = join(' ', map { $_ =~ /\s/ ? qq{"$_"} : $_ } @cmd);
        $qref->enqueue("[worker] cmd: $pretty\n");

        my $cmdline = $pretty . " 2>&1";

        $qref->enqueue("\n=== Finding DLLs and generating Makefile ===\n");

        my $exit = 0;
        if (open(my $fh, "$cmdline |")) {
            $qref->enqueue("[worker] pipe opened, reading output...\n");

            my $line_count = 0;
            my $CMD_line = "";
            while (my $line = <$fh>) {
                $line_count++;
                $qref->enqueue($line);
                if ($line =~ m/^CMD:/) {
                    $CMD_line = $line;
                }
            }

            my $perl_path = $^X;

            my ($volume, $dirs, $file) = File::Spec->splitpath($perl_path);
            my @parts = File::Spec->splitdir($dirs);

            pop @parts;
            pop @parts;
            pop @parts;
            push @parts, "c", "bin";

            my $filter    = $volume . join("/", @parts);
            my $perl_root = lc File::Spec->catdir($volume, @parts);

            my @cmd2 = split / /, $CMD_line;
            my @filtered_libs = grep { m/\Q$filter\E/i } @cmd2;

            $qref->enqueue("\n=== Perl moduled DLLs to include ===\n\n");

            my $wxpar = 'wxpar -o $(EXE)';
            foreach my $lib (@filtered_libs) {
                $wxpar .= " --link $lib ";
                $qref->enqueue("$lib\n");
            }

            $wxpar .= " $script --gui";

            $qref->enqueue("\n=== Makefile with 'wxpar' command ===\n\n");

            $wxpar =~ s/\\/\//g;
            $wxpar =~ s/\Q$filter\E/\$\(CBIN\)/gi;

            my $makefile = <<EOF;
# -- BEGIN MAKEFILE --

CBIN    := "$perl_root"
DIST    := dist
RELEASE := release
EXE     := $exe

clean:
	\@if exist \$(DIST)\* del /Q /F \$(DIST)\* 2>NUL
	\@if exist \$(RELEASE)\* del /Q /F \$(RELEASE)\* 2>NUL

all: exe

exe: prepdirs
	$wxpar
	\@move /Y \$(EXE) \$(DIST)\

prepdirs:
	\@if not exist \$(DIST) mkdir \$(DIST)
	\@if not exist \$(RELEASE) mkdir \$(RELEASE)
# -- END MAKEFILE --

EOF
            $qref->enqueue({ type => 'MAKEFILE', text => $makefile });

            close($fh);
            $exit = $? >> 8;
            $qref->enqueue("[worker] pipe closed, lines=$line_count, rc=$exit\n");
        } else {
            $qref->enqueue("[worker][error] failed to run command pipe: $!\n");
            $exit = 127;
        }

        $qref->enqueue({ type => 'DONE', exit_code => $exit });
        return;
    }, $script, $q)->detach();
}

