sub _collect_iss_values {
    my ($self) = @_;

    my $app_name      = _trim($self->{iss_app_name}->GetValue);
    my $app_exe       = _trim($self->{iss_app_exe}->GetValue);
    my $app_version   = _trim($self->{iss_app_version}->GetValue);
    my $app_publisher = _trim($self->{iss_app_publisher}->GetValue);

    my $appid_raw     = _trim($self->{iss_appid}->GetValue);
    my $dist_exe_path = _trim($self->{iss_dist_exe_path}->GetValue);
    my $output_dir    = _trim($self->{iss_output_dir}->GetValue);
    my $output_base   = _trim($self->{iss_output_base}->GetValue);
    my $icon_path     = _trim($self->{iss_icon_path}->GetValue);

    my $scope_sel = $self->{iss_install_scope}->GetSelection;
    $scope_sel = 0 if !defined($scope_sel) || $scope_sel < 0;
    my $per_user = ($scope_sel == 0) ? 1 : 0;

    my $desktop_icon = $self->{iss_chk_desktop_icon}->GetValue ? 1 : 0;
    my $launch       = $self->{iss_chk_launch}->GetValue       ? 1 : 0;
    my $kill_running = $self->{iss_chk_kill_running}->GetValue ? 1 : 0;

    my $appid = _normalize_appid($appid_raw);

    return (
        $app_name,
        $app_exe,
        $app_version,
        $app_publisher,
        $appid,
        $dist_exe_path,
        $output_dir,
        $output_base,
        $icon_path,
        $per_user,
        $desktop_icon,
        $launch,
        $kill_running,
    );
}

sub generate_iss_preview {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::generate_iss_preview <event_handler>
    # end wxGlade

    my $cur = $self->{notebook_1}->GetSelection;
    if (!defined($cur) || $cur != 1) {
        $self->_append_io("[iss] Not generating preview (ISS tab not active).\n");
        return;
    }

    my $script = _trim($self->{perl_script_path}->GetValue);
    if (!$script) {
        $self->_append_io("[iss] Not generating preview (no script selected).\n");
        return;
    }

    if ($self->{_iss_pending_seed}) {
        $self->_seed_iss_fields_from_script();
    }

    my (
        $app_name,
        $app_exe,
        $app_version,
        $app_publisher,
        $appid,
        $dist_exe_path,
        $output_dir,
        $output_base,
        $icon_path,
        $per_user,
        $desktop_icon,
        $launch,
        $kill_running,
    ) = $self->_collect_iss_values();

    my $appid_effective = $appid || ('{{' . _new_guid_upper() . '}}');

    my $priv_lines = $per_user
        ? "PrivilegesRequired=lowest\nPrivilegesRequiredOverridesAllowed=commandline"
        : "PrivilegesRequired=admin";

    my $setup_icon_line = $icon_path ? "SetupIconFile=$icon_path" : '';

    my $tasks_block = '';
    if ($desktop_icon) {
        $tasks_block = <<'TASKS';
[Tasks]

Name: "desktopicon"; Description: "Create a &desktop icon"; GroupDescription: "Additional icons:"
TASKS
    }

    my $run_block = '';
    if ($launch) {
        $run_block = <<RUN;
[Run]

Filename: "{app}\\{#MyAppExe}"; Description: "Launch {#MyAppName}"; Flags: nowait postinstall skipifsilent
RUN
    }

    my $code_block = '';
    if ($kill_running) {
        $code_block = <<CODE;
[Code]

function InitializeSetup(): Boolean;
var
  ResultCode: Integer;
begin
  // Close running version during upgrade
  Exec(
    ExpandConstant('{cmd}'),
    '/C taskkill /IM "{#MyAppExe}" /T /F >NUL 2>NUL',
    '',
    SW_HIDE,
    ewWaitUntilTerminated,
    ResultCode
  );

  Result := True;
end;
CODE
    }

    my $iss = <<"ISS";
; ------------------------------------------------------------
; Generated by wxPerl GUI Helper for Windows (Inno Setup tab)
; ------------------------------------------------------------

#define MyAppName "$app_name"
#define MyAppExe "$app_exe"
#define MyAppVersion "$app_version"
#define MyAppPublisher "$app_publisher"

[Setup]

AppId=$appid_effective

AppName={#MyAppName}
AppVersion={#MyAppVersion}
AppPublisher={#MyAppPublisher}

DefaultDirName={localappdata}\\Programs\\{#MyAppName}
DefaultGroupName={#MyAppName}

$priv_lines

UninstallDisplayIcon={app}\\{#MyAppExe}

Compression=lzma2
SolidCompression=yes
WizardStyle=modern

OutputDir=$output_dir
OutputBaseFilename=$output_base
ISS

    if ($setup_icon_line) {
        $iss .= $setup_icon_line . "\n";
    }

    $iss .= <<"ISS2";

[Files]

Source: "$dist_exe_path"; DestDir: "{app}"; Flags: ignoreversion

$tasks_block
[Icons]

; Start Menu shortcut
ISS2

    my $icon_param = '';
    if (defined($icon_path) && length($icon_path)) {
        $icon_param = qq{; IconFilename: "$icon_path"};
    }

    my $start_menu_line =
        qq{Name: "{userprograms}\\{#MyAppName}\\{#MyAppName}"; Filename: "{app}\\{#MyAppExe}"} . $icon_param;

    $iss .= $start_menu_line . "\n";

    $iss .= <<"ISS3";

; Uninstall shortcut
Name: "{userprograms}\\{#MyAppName}\\Uninstall {#MyAppName}"; Filename: "{uninstallexe}"
ISS3

    if ($desktop_icon) {
        my $icon_param = '';
        if (defined($icon_path) && length($icon_path)) {
            $icon_param = qq{; IconFilename: "$icon_path"};
        }

        my $line =
            qq{Name: "{userdesktop}\\{#MyAppName}"; Filename: "{app}\\{#MyAppExe}"; Tasks: desktopicon} . $icon_param;

        $iss .= "\n; Optional desktop shortcut\n$line\n";
    }

    $iss .= "\n";
    $iss .= $run_block  if $run_block;
    $iss .= "\n";
    $iss .= $code_block if $code_block;

    $self->_set_preview_text($iss);
    $self->{_q}->enqueue("[iss] Preview generated.\n");
}

sub save_iss_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::save_iss_file <event_handler>
